const body = $json.body || $json;
const event = body.event || 'unknown';
const data = body.data || body;

let title = '', description = '', color = 16776960; // yellow

switch(event) {
  case 'report_created':
    title = '🚨 New Report';
    description = `**${data.reporter || 'User'}** reported **${data.target || 'content'}**\nReason: ${data.reason || 'No reason'}`;
    color = 16744448; // orange
    break;
  case 'ban_created':
    title = '🔨 User Banned';
    description = `**${data.username || 'Unknown'}** banned by **${data.moderator || 'System'}**\nReason: ${data.reason || 'No reason'}\nDuration: ${data.duration || 'Permanent'}`;
    color = 16711680; // red
    break;
  case 'ticket_created':
    title = '🎫 New Support Ticket';
    description = `**${data.username || 'User'}**: ${data.subject || data.title || 'No subject'}`;
    color = 3447003; // blue
    break;
  case 'user_registered':
    title = '👋 New User';
    description = `**${data.username || 'Unknown'}** registered`;
    color = 65280; // green
    break;
  default:
    title = `📋 ${event}`;
    description = JSON.stringify(data).slice(0, 500);
}

return [{ json: { title, description, color, event, timestamp: new Date().toISOString() } }];
